import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.BD8VCRzL.js";const g=JSON.parse('{"title":"Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"faq/index.md","filePath":"faq/index.md"}'),r={name:"faq/index.md"};function n(s,e,d,h,l,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h1><p>Answers to common questions about using Aurelius Ledger.</p><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><h3 id="what-should-i-type-when-logging-a-trade" tabindex="-1">What should I type when logging a trade? <a class="header-anchor" href="#what-should-i-type-when-logging-a-trade" aria-label="Permalink to &quot;What should I type when logging a trade?&quot;">​</a></h3><p>Anything that describes what happened. Be honest and specific. Examples:</p><ul><li>&quot;Longed NQ at 17500, made $500&quot;</li><li>&quot;Short ES, lost $200, chased the entry&quot;</li><li>&quot;Waited for the setup, exited at target, +$300&quot;</li><li>&quot;FOMO&#39;d into the breakout, knew it was wrong, -$150&quot;</li></ul><p>The more context you give, the better the AI can understand your trade.</p><h3 id="what-if-i-make-a-typo" tabindex="-1">What if I make a typo? <a class="header-anchor" href="#what-if-i-make-a-typo" aria-label="Permalink to &quot;What if I make a typo?&quot;">​</a></h3><p>Just resubmit. The system processes each entry independently. If you made a mistake, type the correct version and submit again.</p><h3 id="can-i-edit-a-trade-after-logging-it" tabindex="-1">Can I edit a trade after logging it? <a class="header-anchor" href="#can-i-edit-a-trade-after-logging-it" aria-label="Permalink to &quot;Can I edit a trade after logging it?&quot;">​</a></h3><p>Not in the current version. If you need to correct something, log a new trade with the corrected info, or contact support for help.</p><h3 id="how-long-is-a-session" tabindex="-1">How long is a &quot;session&quot;? <a class="header-anchor" href="#how-long-is-a-session" aria-label="Permalink to &quot;How long is a &quot;session&quot;?&quot;">​</a></h3><p>A session runs from when you start logging trades until you stop for more than 30 minutes. After 30 minutes of inactivity, any new trade starts a fresh session.</p><p>Each session is tracked separately, so you can see how different trading days went.</p><h2 id="understanding-your-data" tabindex="-1">Understanding Your Data <a class="header-anchor" href="#understanding-your-data" aria-label="Permalink to &quot;Understanding Your Data&quot;">​</a></h2><h3 id="what-do-the-discipline-and-agency-scores-mean" tabindex="-1">What do the discipline and agency scores mean? <a class="header-anchor" href="#what-do-the-discipline-and-agency-scores-mean" aria-label="Permalink to &quot;What do the discipline and agency scores mean?&quot;">​</a></h3><p><strong>Discipline</strong> — Did you follow your rules?</p><ul><li>+1: You waited for your setup, followed your plan</li><li>0: Neutral</li><li>-1: You deviated — chased, overtraded, ignored rules</li></ul><p><strong>Agency</strong> — Are you in control?</p><ul><li>+1: You made an intentional decision</li><li>0: Neutral</li><li>-1: You reacted emotionally — revenge trading, FOMO, fear</li></ul><h3 id="why-did-i-get-a-1-discipline-score" tabindex="-1">Why did I get a -1 discipline score? <a class="header-anchor" href="#why-did-i-get-a-1-discipline-score" aria-label="Permalink to &quot;Why did I get a -1 discipline score?&quot;">​</a></h3><p>Common triggers include:</p><ul><li>Using words like &quot;chased,&quot; &quot;FOMO,&quot; &quot;revenge,&quot; &quot;too early,&quot; &quot;knew it was wrong&quot;</li><li>Taking a trade that does not match your stated setup</li><li>Entering without waiting for your confirmation signal</li><li>Increasing size after a loss</li></ul><p>The AI looks at the words you use and the context of your description.</p><h3 id="what-does-insufficient-signal-mean" tabindex="-1">What does &quot;insufficient signal&quot; mean? <a class="header-anchor" href="#what-does-insufficient-signal-mean" aria-label="Permalink to &quot;What does &quot;insufficient signal&quot; mean?&quot;">​</a></h3><p>That means the AI could not confidently determine your score based on what you typed. Your description was too vague.</p><p>To get a more accurate score, be more descriptive:</p><ul><li>Instead of &quot;won on ES,&quot; say &quot;waited for the pullback to the 9 EMA, entered long, hit target for +$400&quot;</li></ul><h3 id="how-is-tilt-detected" tabindex="-1">How is tilt detected? <a class="header-anchor" href="#how-is-tilt-detected" aria-label="Permalink to &quot;How is tilt detected?&quot;">​</a></h3><p>The system watches for patterns in your discipline and agency scores. If you get 3 consecutive -1 scores (either discipline or agency), you will see an amber warning. At 4+, it turns orange.</p><p>The warning is triggered by patterns, not by individual trades. A single bad trade will not trigger it.</p><h3 id="what-does-the-warning-bar-mean" tabindex="-1">What does the warning bar mean? <a class="header-anchor" href="#what-does-the-warning-bar-mean" aria-label="Permalink to &quot;What does the warning bar mean?&quot;">​</a></h3><ul><li><strong>Amber (yellow):</strong> 3 consecutive discipline or agency -1 scores. You might be slipping.</li><li><strong>Orange:</strong> 4+ consecutive discipline or agency -1 scores. You are likely tilted — consider stepping away.</li></ul><p>The warning is not a punishment. It is a signal to pay attention to what is happening.</p><h2 id="privacy-and-data" tabindex="-1">Privacy and Data <a class="header-anchor" href="#privacy-and-data" aria-label="Permalink to &quot;Privacy and Data&quot;">​</a></h2><h3 id="is-my-data-private" tabindex="-1">Is my data private? <a class="header-anchor" href="#is-my-data-private" aria-label="Permalink to &quot;Is my data private?&quot;">​</a></h3><p>Yes. Your trading data is stored securely and associated with your account. It is used only to power your dashboard and insights.</p><p>The AI does not share your data with anyone. Your trades are not visible to other users.</p><h3 id="does-the-ai-remember-my-past-sessions" tabindex="-1">Does the AI remember my past sessions? <a class="header-anchor" href="#does-the-ai-remember-my-past-sessions" aria-label="Permalink to &quot;Does the AI remember my past sessions?&quot;">​</a></h3><p>No. Each session is independent. The AI does not carry over information from one day to the next. It only looks at your current session data to generate insights.</p><h3 id="can-i-delete-my-data" tabindex="-1">Can I delete my data? <a class="header-anchor" href="#can-i-delete-my-data" aria-label="Permalink to &quot;Can I delete my data?&quot;">​</a></h3><p>Yes. Contact support to request data deletion. You can also export your data if you want to keep a copy.</p><h3 id="what-data-do-you-collect" tabindex="-1">What data do you collect? <a class="header-anchor" href="#what-data-do-you-collect" aria-label="Permalink to &quot;What data do you collect?&quot;">​</a></h3><p>We collect what you type (trade descriptions), the extracted trade details (direction, P&amp;L, scores), and session timestamps. We do not collect personal information beyond your email.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="the-dashboard-is-not-loading" tabindex="-1">The dashboard is not loading <a class="header-anchor" href="#the-dashboard-is-not-loading" aria-label="Permalink to &quot;The dashboard is not loading&quot;">​</a></h3><p>Try refreshing the page. If the problem persists, check your internet connection or try clearing your browser cache.</p><h3 id="my-trade-did-not-go-through" tabindex="-1">My trade did not go through <a class="header-anchor" href="#my-trade-did-not-go-through" aria-label="Permalink to &quot;My trade did not go through&quot;">​</a></h3><p>Make sure you pressed Enter or clicked &quot;Log Trade.&quot; You should see a green flash on the input if it succeeded.</p><p>If it still does not work, try logging the trade again. If the problem continues, contact support.</p><h3 id="the-charts-are-not-updating" tabindex="-1">The charts are not updating <a class="header-anchor" href="#the-charts-are-not-updating" aria-label="Permalink to &quot;The charts are not updating&quot;">​</a></h3><p>The charts update after each trade. If they are not updating:</p><ul><li>Refresh the page</li><li>Make sure JavaScript is enabled in your browser</li><li>Check your internet connection</li></ul><h3 id="i-disagree-with-a-score-—-what-can-i-do" tabindex="-1">I disagree with a score — what can I do? <a class="header-anchor" href="#i-disagree-with-a-score-—-what-can-i-do" aria-label="Permalink to &quot;I disagree with a score — what can I do?&quot;">​</a></h3><p>Scores are based on your description. If you disagree, try describing trades more explicitly in the future. The score is a starting point for reflection, not a definitive judgment.</p><h2 id="tips-and-best-practices" tabindex="-1">Tips and Best Practices <a class="header-anchor" href="#tips-and-best-practices" aria-label="Permalink to &quot;Tips and Best Practices&quot;">​</a></h2><h3 id="when-is-the-best-time-to-log-a-trade" tabindex="-1">When is the best time to log a trade? <a class="header-anchor" href="#when-is-the-best-time-to-log-a-trade" aria-label="Permalink to &quot;When is the best time to log a trade?&quot;">​</a></h3><p>Log right after you close a trade, while the details are fresh. The trade entry box is always at the bottom of your screen, so it is easy to do between trades.</p><h3 id="how-do-i-get-better-insights" tabindex="-1">How do I get better insights? <a class="header-anchor" href="#how-do-i-get-better-insights" aria-label="Permalink to &quot;How do I get better insights?&quot;">​</a></h3><p>Log more trades. Insights unlock after 5 trades and get richer as you log more. Try to describe your trades with context — what setup you were looking for, how you felt, whether you followed your plan.</p><h3 id="should-i-log-every-trade" tabindex="-1">Should I log every trade? <a class="header-anchor" href="#should-i-log-every-trade" aria-label="Permalink to &quot;Should I log every trade?&quot;">​</a></h3><p>Yes, for the best results. Even scratched trades and small losers. The more complete your data, the more useful the insights.</p><h3 id="what-if-i-trade-multiple-instruments" tabindex="-1">What if I trade multiple instruments? <a class="header-anchor" href="#what-if-i-trade-multiple-instruments" aria-label="Permalink to &quot;What if I trade multiple instruments?&quot;">​</a></h3><p>The system does not differentiate between instruments in the main dashboard. Log your trades as usual — the system looks at patterns in your behavior, not which contract you traded.</p><hr><p>Still have questions? Reach out to support and we will help you out.</p>',66)])])}const p=t(r,[["render",n]]);export{g as __pageData,p as default};
